CREATE TABLE IF NOT EXISTS datap4k_ships_raw          (id SERIAL PRIMARY KEY, data JSONB NOT NULL, game_version TEXT, imported_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS datap4k_ground_vehicles_raw(id SERIAL PRIMARY KEY, data JSONB NOT NULL, game_version TEXT, imported_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS datap4k_armor_raw          (id SERIAL PRIMARY KEY, data JSONB NOT NULL, game_version TEXT, imported_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS datap4k_weapons_raw        (id SERIAL PRIMARY KEY, data JSONB NOT NULL, game_version TEXT, imported_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS datap4k_components_raw     (id SERIAL PRIMARY KEY, data JSONB NOT NULL, game_version TEXT, imported_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS datap4k_items_raw          (id SERIAL PRIMARY KEY, data JSONB NOT NULL, game_version TEXT, imported_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS datap4k_shops_raw          (id SERIAL PRIMARY KEY, data JSONB NOT NULL, game_version TEXT, imported_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS datap4k_crafting_raw       (id SERIAL PRIMARY KEY, data JSONB NOT NULL, game_version TEXT, imported_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS datap4k_mining_raw         (id SERIAL PRIMARY KEY, data JSONB NOT NULL, game_version TEXT, imported_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS datap4k_mining_gear_raw    (id SERIAL PRIMARY KEY, data JSONB NOT NULL, game_version TEXT, imported_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS datap4k_loot_tables_raw    (id SERIAL PRIMARY KEY, data JSONB NOT NULL, game_version TEXT, imported_at TIMESTAMPTZ DEFAULT NOW());

parameters.jsCode:
const FILE_TABLE_MAP = {
  'ships.json':          'datap4k_ships_raw',
  'ground_vehicles.json':'datap4k_ground_vehicles_raw',
  'armor.json':          'datap4k_armor_raw',
  'weapons.json':        'datap4k_weapons_raw',
  'components.json':     'datap4k_components_raw',
  'items.json':          'datap4k_items_raw',
  'shops.json':          'datap4k_shops_raw',
  'crafting.json':       'datap4k_crafting_raw',
  'mining.json':         'datap4k_mining_raw',
  'mining_gear.json':    'datap4k_mining_gear_raw',
  'loot_tables.json':    'datap4k_loot_tables_raw',
};

const binaryData = ($binary && $binary.data) ? $binary.data : {};
const fileName = binaryData.fileName || $json.filename || $json.fileName || '';
if (!fileName) throw new Error('Missing filename — no binary.data.fileName');

const tableName = FILE_TABLE_MAP[fileName];
if (!tableName) throw new Error('Unknown DataPack file: "' + fileName + '"');

const d = $json.data || $json;

const meta = d.meta || {};
const gameVersion = meta.game_version || 'unknown';
let records = [];

if (fileName === 'ships.json') {
  records = d.ships || [];
}
else if (fileName === 'ground_vehicles.json') {
  records = ((d.vehicles || {}).list) || [];
}
else if (fileName === 'armor.json') {
  var slots = ((d.armor || {}).slots) || [];
  records = slots.reduce(function(acc, slot) { return acc.concat(slot.items || []); }, []);
}
else if (fileName === 'weapons.json') {
  var cats = ((d.weapons || {}).categories) || [];
  records = cats.reduce(function(acc, cat) {
    var catId = cat['category-id'];
    return acc.concat((cat.items || []).map(function(item) {
      return Object.assign({}, item, { category: catId });
    }));
  }, []);
}
else if (fileName === 'components.json') {
  var cats = ((d.components || {}).categories) || [];
  records = cats.reduce(function(acc, cat) {
    var catId = cat['category-id'];
    return acc.concat((cat.items || []).map(function(item) {
      return Object.assign({}, item, { 'category-id': catId });
    }));
  }, []);
}
else if (fileName === 'items.json') {
  var cats = ((d.items || {}).categories) || [];
  records = cats.reduce(function(acc, cat) {
    var catId = cat['category-id'];
    return acc.concat((cat.items || []).map(function(item) {
      return Object.assign({}, item, { 'category-id': catId });
    }));
  }, []);
}
else if (fileName === 'shops.json') {
  var shops = d.shops || [];
  records = shops.reduce(function(acc, s) {
    return acc.concat((s.inventory || []).map(function(item) {
      return Object.assign({}, item, { shop: s.shop, location: s.location });
    }));
  }, []);
}
else if (fileName === 'crafting.json') {
  var cats = ((d.crafting || {}).categories) || [];
  records = cats.reduce(function(acc, cat) {
    var catId = cat['category-id'];
    return acc.concat((cat.items || []).reduce(function(acc2, item) {
      return acc2.concat((item.variants || []).map(function(v) {
        return Object.assign({}, v, {
          'category-id': catId,
          'family': item.family,
          'manufacturer': item.manufacturer
        });
      }));
    }, []));
  }, []);
}
else if (fileName === 'mining.json') {
  records = [].concat(
    (d.elements || []).map(function(r) { return Object.assign({}, r, { _section: 'elements' }); }),
    (d.compositions || []).map(function(r) { return Object.assign({}, r, { _section: 'compositions' }); }),
    (d['planet-mineables'] || []).map(function(r) { return Object.assign({}, r, { _section: 'planet-mineables' }); })
  );
}
else if (fileName === 'mining_gear.json') {
  var cats = ((d['mining-gear'] || {}).categories) || [];
  records = cats.reduce(function(acc, cat) {
    var catId = cat['category-id'];
    return acc.concat((cat.items || []).map(function(item) {
      return Object.assign({}, item, { category: catId });
    }));
  }, []);
}
else if (fileName === 'loot_tables.json') {
  var cats = ((d.loot || {}).categories) || [];
  records = cats.reduce(function(acc, cat) {
    var catId = cat['category-id'];
    var catName = cat['category-name'] || catId;
    return acc.concat((cat['loot-tables'] || []).map(function(table) {
      return Object.assign({}, table, { 'category-id': catId, 'category-name': catName });
    }));
  }, []);
}

return [{
  json: {
    tableName: tableName,
    fileName: fileName,
    gameVersion: gameVersion,
    recordCount: records.length,
    records: records
  }
}];

const { tableName, gameVersion, records } = $json;

if (!tableName) throw new Error('Missing tableName');
if (!Array.isArray(records)) throw new Error('records is not an array');
if (!/^[a-zA-Z0-9_]+$/.test(tableName)) throw new Error('Unsafe table name: ' + tableName);

const gv = String(gameVersion || 'unknown').replace(/'/g, "''");
const sqlParts = [];


if (records.length > 0) {
  const BATCH = 500;
  for (let i = 0; i < records.length; i += BATCH) {
    const chunk = records.slice(i, i + BATCH);
    const values = chunk.map(function(r) {
      const escaped = JSON.stringify(r).replace(/'/g, "''");
      return "('" + escaped + "'::jsonb, '" + gv + "', NOW())";
    }).join(',');
    sqlParts.push('INSERT INTO ' + tableName + ' (data, game_version, imported_at) VALUES ' + values + ';');
  }
}

return [{ json: { sql: sqlParts.join('\n'), tableName: tableName, recordCount: records.length } }];

const output = [];

for (const item of items) {
  if (!item.binary) continue;

  for (const key of Object.keys(item.binary)) {
    const file = item.binary[key];

    output.push({
      binary: {
        data: file
      },
      json: {
        filename: file.fileName || '',
        size: file.fileSize || file.bytes || 0,
        type: file.mimeType || file.fileType || '',
        extension: file.fileExtension || ''
      }
    });
  }
}

return output;

